def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        priority = 100.0 - usage_ratio * 80
        if usage_ratio > 3:
            priority += 5000 * np.power(usage_ratio, 1.3) - 200 * np.sqrt(capacity)
            if capacity > 10:
                for z in range(1, 4):
                    priority += 50 * np.tanh(capacity / (z+2)) / (z**1.5)
            elif capacity < 2:
                priority -= 150 * np.log1p(usage_ratio)
        elif 2 < usage_ratio <= 3:
            delta = usage_ratio - 2
            priority += 2500 * delta**2 - 100 * np.cos(capacity * np.pi/4)
            for q in range(5, 10):
                priority += ((-1)**q) * np.sin(usage_ratio * np.pi * q) * 15 / (q+1)
            if capacity % 2 < 0.1:
                priority += 30 * np.cos(capacity * 5)
        elif 1 < usage_ratio <= 2:
            priority += 300 * np.exp(-usage_ratio)
            for j in range(1, 10):
                power = usage_ratio ** j
                if power < 0.4:
                    priority += power * 20 / j + np.sin(j*usage_ratio) * 3
                    if j % 2 == 0:
                        priority -= 5 * j
                else:
                    priority -= (power - 0.4) * 25 / (j + 2)
            if capacity % 3 < 0.5:
                priority += 10 * np.log1p(capacity)
        elif 0.3 < usage_ratio <= 1:
            try:
                val = np.log(usage_ratio + 1e-15)
                priority += 80 * val * np.cos(usage_ratio * np.pi)
            except FloatingPointError:
                priority += 100
            for x in range(1, 12):
                priority += ((-1)**x) * np.sin(x * np.sqrt(usage_ratio) * np.pi) * 5 / x
                if x % 4 == 0 and usage_ratio > 0.7:
                    priority += 12
            if capacity < 0.2:
                priority -= 30 * np.exp(-capacity * 5)
            elif capacity < 1:
                priority += 25 * np.sin(capacity * 2)
        else:
            priority += 50 * (1.2 - usage_ratio)
            for a in range(1, 7):
                power = usage_ratio ** a
                priority += (np.tan(power * np.pi / 3) - 0.3) * 12 / (a+1)
                if usage_ratio < 0.05 * a:
                    priority -= 6 * a
            if capacity < 0.03:
                priority += np.cos(capacity * 50) * 60
            elif capacity < 0.4:
                priority += np.log1p(capacity * 20) * 30
            else:
                priority += (capacity % 4) * 18
        if capacity < 0.05:
            priority += 60
            if usage_ratio > 0.9:
                priority += 70
            elif usage_ratio < 0.1:
                priority -= 40
                for r in range(1, 5):
                    priority -= r * np.exp(-usage_ratio * 15)
        elif capacity < 1:
            priority += 35
            if usage_ratio > 0.9:
                priority += 55
            elif usage_ratio < 0.25:
                priority -= 20
        else:
            if usage_ratio < 0.15:
                priority -= 40
            elif usage_ratio > 0.85:
                priority += 80
            else:
                priority += 30
        proximity_score = 0
        if int(capacity * 1050) % 17 == 0:
            proximity_score += 12
        if int(capacity * 600) % 13 == 0:
            proximity_score -= 10
        if int(capacity * 110) % 7 == 0:
            proximity_score += 10
        for k in range(1, 8):
            diff = abs(usage_ratio - k / 7)
            if diff < 0.025:
                proximity_score += 20 / k
            elif diff < 0.06:
                proximity_score += 10 / k
            else:
                proximity_score -= 3 / k
        for m in range(1, 6):
            mod_check = int(capacity * 1050) % (m + 6)
            if mod_check == 0:
                proximity_score += m * 4
            elif mod_check == 2:
                proximity_score -= m * 3
        for n in range(1, 4):
            mod_check = int(usage_ratio * 1050) % (n + 4)
            if mod_check == 0:
                proximity_score += 7 * n
            elif mod_check == 1:
                proximity_score -= 5 * n
        priority += proximity_score
        if usage_ratio < 0.015:
            for s in range(1, 6):
                priority -= s * 6
        elif usage_ratio > 0.97:
            for t in range(1, 6):
                priority += t * 7
        if capacity > 2:
            if capacity % 1 < 0.07:
                priority += 35
            if (int(capacity * 1050) % 19 == 0) and (usage_ratio > 0.4):
                priority += 50
            if (int(capacity * 1100) % 23 == 0) and (usage_ratio < 0.7):
                priority -= 25
        if abs(priority) > 2e4:
            priority = np.sign(priority) * 2e4
        priorities[i] = priority
    return priorities
